@ExtendWith(MockitoExtension::class)
class CallServiceTest {

    @Mock
    private lateinit var callRepository: CallRepository

    @Mock
    private lateinit var statisticsRepository: CallStatisticsRepository

    @InjectMocks
    private lateinit var callService: CallService

    @Test
    fun `should initiate call between two users`() {
        // given
        val initiatorId = "user-1"
        val recipientId = "user-2"
        val callEntity = CallEntity(
            initiatorUserId = initiatorId,
            recipientUserId = recipientId,
            status = 0
        )
        `when`(callRepository.save(any())).thenReturn(callEntity)

