        val result = callService.initiateCall(initiatorId, recipientId)

        // then
        assertThat(result.initiatorUserId).isEqualTo(initiatorId)
        assertThat(result.status).isEqualTo(0)
        verify(callRepository).save(any())
    }

    @Test
    fun `should reject call if user is already in another call`() {
        // given
        val userId = "user-1"
        `when`(callRepository.findActiveCallByUserId(userId))
            .thenReturn(CallEntity(initiatorUserId = userId, recipientUserId = "user-3"))

        // when & then
        assertThrows<CallAlreadyActiveException> {
            callService.initiateCall(userId, "user-2")
        }
    }
