### 4. 버그가 있을 만한 복잡한 로직

#### 4.1 동시성 문제 (Race Condition)

**위험 지점:**
```kotlin
// 문제: 두 사용자가 동시에 같은 사람에게 통화 시작할 수 있음
@Transactional
fun initiateCall(initiatorId: String, recipientId: String): CallEntity {
    val activeCall = callRepository.findActiveCallByUserId(recipientId)  // 체크
    if (activeCall != null) {
        throw CallAlreadyActiveException()
    }
    // 여기서 다른 스레드가 개입 가능 (Race Condition)
    return callRepository.save(CallEntity(...))  // 저장
}
```

**해결책:**
- `@Lock(LockModeType.PESSIMISTIC_WRITE)` 사용
- DB 레벨 UNIQUE 제약조건 추가

#### 4.2 통화 시간 계산 오류

**위험 지점:**
```kotlin
// 문제: endedAt이 null일 수 있음 (통화 진행중 상태)
fun updateCallStatistics(call: CallEntity): Long {
    return ChronoUnit.SECONDS.between(call.createdAt, call.endedAt)  
    // null pointer exception 가능!
}
```

**해결책:**
```kotlin
fun updateCallStatistics(call: CallEntity): Long {
    val end = call.endedAt ?: LocalDateTime.now()
    return ChronoUnit.SECONDS.between(call.createdAt, end)
}
```

#### 4.3 상태 전이 검증 부족

**위험 지점:**
```kotlin
// 문제: 상태 전이 검증 없음
// 0(대기) → 1(연결) ✓
// 1(연결) → 1(연결) ✗ (불가능)
// 2(종료) → 1(연결) ✗ (불가능)

@Transactional
fun acceptCall(callId: String): CallEntity {
    val call = callRepository.findById(callId).orElseThrow()
    call.status = 1  // 상태 검증 없음!
    return callRepository.save(call)
}
```

**해결책:**
```kotlin
fun acceptCall(callId: String): CallEntity {
    val call = callRepository.findById(callId).orElseThrow()
    if (call.status != 0) {  // 대기 상태만 가능
        throw InvalidCallStateException("Call is already ${call.status}")
    }
    call.status = 1
    return callRepository.save(call)
}
```

#### 4.4 매너점수 조작 가능성

**위험 지점:**
```kotlin
// 문제: 매너점수가 음수가 될 수 있음
fun decreaseMannerScore(userId: String, points: Int): Int {
    val stats = statisticsRepository.findByUserId(userId)
    stats.mannerScore -= points  // -10까지도 가능!
    return statisticsRepository.save(stats).mannerScore
}
```

**해결책:**
```kotlin
fun decreaseMannerScore(userId: String, points: Int): Int {
    val stats = statisticsRepository.findByUserId(userId)
    stats.mannerScore = maxOf(0, stats.mannerScore - points)  // 최소 0
    return statisticsRepository.save(stats).mannerScore
}
```

#### 4.5 통화 거절/취소 후 재발신 타이밍

**위험 지점:**
```kotlin
// 문제: 거절된 통화가 즉시 삭제되면, 2초 후 같은 사람이 다시 발신 가능
@Transactional
fun rejectCall(callId: String): Boolean {
    callRepository.deleteById(callId)  // 즉시 삭제
    return true
}
```

**해결책:**
- soft delete 사용 (deletedAt 컬럼 추가)
- 거절 후 쿨다운 시간 설정 (예: 30초)

---

### 5. 프로토콜 버퍼 정의 (call_service.proto)

```protobuf
syntax = "proto3";
package call;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.call";

service CallService {
    rpc InitiateCall(InitiateCallRequest) returns (CallResponse);
    rpc AcceptCall(AcceptCallRequest) returns (CallResponse);
    rpc RejectCall(RejectCallRequest) returns (CallResponse);
    rpc EndCall(EndCallRequest) returns (CallResponse);
    rpc GetActiveCall(GetActiveCallRequest) returns (CallResponse);
    rpc GetCallHistory(GetCallHistoryRequest) returns (CallHistoryResponse);
}

message CallResponse {
    string id = 1;
    string initiator_user_id = 2;
    string recipient_user_id = 3;
    int32 status = 4;
    int64 duration_seconds = 5;
    string created_at = 6;
    string ended_at = 7;
}

message InitiateCallRequest {
    string initiator_id = 1;
    string recipient_id = 2;
}

// ... 기타 Request/Response 메시지
```

---

### 6. GraphQL 스키마 (call.graphqls)

```graphql
type Call {
    id: ID!
    initiator: SimpleUser!
    recipient: SimpleUser!
    status: CallStatus!
    durationSeconds: Int!
    createdAt: String!
    endedAt: String
}

enum CallStatus {
    WAITING
    CONNECTED
    ENDED
    REJECTED
}

type CallStatistics {
    userId: ID!
    totalCallCount: Int!
    averageDurationSeconds: Int!
    mannerScore: Int!
}

input InitiateCallInput {
    recipientId: ID!
}

extend type Query {
    activeCall: Call
    callHistory(limit: Int, offset: Int): [Call!]!
    callStatistics: CallStatistics!
}

extend type Mutation {
    initiateCall(input: InitiateCallInput!): Call!
    acceptCall(callId: ID!): Call!
    rejectCall(callId: ID!): Boolean!
    endCall(callId: ID!): Call!
}
```

